import 'package:baseball_detector_flutter/views/pages/ai_coach_report/components/strikeout_strategy_expansion_tile.dart';
import 'package:baseball_detector_flutter/views/pages/home/home_page.dart';

/// AIコーチ レポートのセクション概要（Card一覧）

class AiCoachReportPage extends ConsumerWidget {
  const AiCoachReportPage({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final reportAsync = ref.watch(aiCoachReportProvider);
    final theme = Theme.of(context);
    final colorScheme = theme.colorScheme;
    final sectionTitleStyle = theme.textTheme.titleMedium?.copyWith(
      fontWeight: FontWeight.w600,
      color: colorScheme.onSurface,
    );
    final sectionSubtitleStyle = theme.textTheme.bodySmall?.copyWith(
      color: colorScheme.onSurfaceVariant,
    );

    return Scaffold(
      appBar: CustomAppBar(
        title: '投手分析レポート（プレビュー）',
        isBackNavigation: true,
      ),
      body: SafeArea(
        child: Padding(
          padding: HomePage.bodyPadding,
          child: reportAsync.when(
            loading: () => const Center(child: CircularProgressIndicator()),
            error: (e, st) {
              debugPrint('$e $st');
              return Padding(
                padding: const EdgeInsets.all(24.0),
                child: Text(
                  'レポートの読み込みに失敗しました: $e',
                  style: theme.textTheme.bodyMedium?.copyWith(
                    color: colorScheme.error,
                  ),
                ),
              );
            },
            data: (report) => SingleChildScrollView(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.stretch,
                children: [
                  // 球種別の特徴
                  PitchFeaturesExpansionTile(
                    pitchFeatures: report.pitchFeatures,
                    titleStyle: sectionTitleStyle,
                  ),
                  const Gap(8),

                  // 良い点・改善点
                  ProsConsExpansionTile(
                    prosCons: report.prosCons,
                    titleStyle: sectionTitleStyle,
                    subtitleStyle: sectionSubtitleStyle,
                  ),
                  const Gap(8),

                  // カウント別推奨配球
                  CountStrategyExpansionTile(
                    entries: report.countRecommendations,
                    titleStyle: sectionTitleStyle,
                    subtitleStyle: sectionSubtitleStyle,
                  ),
                  const Gap(8),

                  // 三振が取れない場合の対策
                  StrikeoutStrategyExpansionTile(
                    strategies: report.strikeoutStrategies,
                    titleStyle: sectionTitleStyle,
                    subtitleStyle: sectionSubtitleStyle,
                  ),
                  const Gap(8),

                  // 左打者に打たれる場合の対策
                  LeftyStrategyExpansionTile(
                    strategies: report.leftyStrategies,
                    titleStyle: sectionTitleStyle,
                    subtitleStyle: sectionSubtitleStyle,
                  ),
                  const Gap(8),

                  // 推奨投球コース
                  PitchZonesExpansionTile(
                    items: report.pitchZones,
                    titleStyle: sectionTitleStyle,
                    subtitleStyle: sectionSubtitleStyle,
                  ),
                  const Gap(8),

                  // 新球種の提案
                  NewPitchExpansionTile(
                    proposals: report.newPitches,
                    titleStyle: sectionTitleStyle,
                    subtitleStyle: sectionSubtitleStyle,
                  ),
                  const Gap(8),

                  // アクションアイテム
                  ActionItemsExpansionTile(
                    items: report.actionPlans,
                    titleStyle: sectionTitleStyle,
                    subtitleStyle: sectionSubtitleStyle,
                  ),
                ],
              ),
            ),
          ),
        ),
      ),
    );
  }
}

