import 'package:flutter/material.dart';

// Package imports:
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/ai_coach/pros_cons.dart';
import 'package:baseball_detector_flutter/views/pages/ai_coach_report/components/common.dart';
import 'package:baseball_detector_flutter/views/pages/ai_coach_report/components/expansion_tile_card.dart';

class ProsConsExpansionTile extends HookConsumerWidget {
  const ProsConsExpansionTile({
    required this.prosCons,
    this.titleStyle,
    this.subtitleStyle,
    super.key,
  });

  final ProsCons prosCons;
  final TextStyle? titleStyle;
  final TextStyle? subtitleStyle;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final pros = prosCons.pros;
    final cons = prosCons.cons;
    final theme = Theme.of(context);
    final scheme = theme.colorScheme;
    final effectiveTitleStyle = titleStyle ??
        theme.textTheme.titleMedium?.copyWith(
          fontWeight: FontWeight.w600,
          color: scheme.onSurface,
        );
    final effectiveSubtitleStyle = subtitleStyle ??
        theme.textTheme.bodySmall?.copyWith(
          color: scheme.onSurfaceVariant,
        );
    final positiveHeadingStyle = theme.textTheme.titleSmall?.copyWith(
      fontWeight: FontWeight.w600,
      color: scheme.primary,
    );
    final negativeHeadingStyle = theme.textTheme.titleSmall?.copyWith(
      fontWeight: FontWeight.w600,
      color: scheme.error,
    );

    return ExpansionTileCard(
      titleBuilder: (icon) => Row(
        mainAxisAlignment: MainAxisAlignment.spaceBetween,
        children: [
          Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Text(
                '良い点・改善点',
                style: effectiveTitleStyle,
              ),
              const Gap(4),
              Text(
                '良い点 ${pros.length} / 改善点 ${cons.length}',
                style: effectiveSubtitleStyle,
              ),
            ],
          ),
          icon,
        ],
      ),
      children: [
        if (pros.isNotEmpty) ...[
          pointBox(
            iconData: Icons.check_circle,
            iconColor: scheme.primary,
            heading: '良い点',
            headingStyle: positiveHeadingStyle,
            items: [for (final p in pros) '${p.title}\n${p.detail}'],
          ),
        ],
        if (cons.isNotEmpty) ...[
          pointBox(
            iconData: Icons.warning,
            iconColor: scheme.error,
            heading: '改善点',
            headingStyle: negativeHeadingStyle,
            items: [for (final p in cons) '${p.title}\n${p.detail}'],
          ),
        ],
      ],
    );
  }

  Widget pointBox({
    required IconData iconData,
    required Color iconColor,
    required String heading,
    required TextStyle? headingStyle,
    required List<String> items,
  }) {
    return CardSurface(
      child: Padding(
        padding: const EdgeInsets.all(8),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Row(
              children: [
                Icon(iconData, color: iconColor, size: 20),
                const Gap(8),
                Text(
                  heading,
                  style: headingStyle,
                ),
              ],
            ),
            const Gap(8),
            ...List.generate(items.length,
                (i) => NumberedBullet(index: i + 1, text: items[i])),
          ],
        ),
      ),
    );
  }
}

