// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:gap/gap.dart';

// Project imports:
import 'package:baseball_detector_flutter/gen/assets.gen.dart';

class SectionTitle extends StatelessWidget {
  const SectionTitle(this.text, {super.key});
  final String text;
  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);
    final colorScheme = theme.colorScheme;
    return Text(
      text,
      style: theme.textTheme.titleMedium?.copyWith(
        fontWeight: FontWeight.w700,
        color: colorScheme.onSurface,
      ),
    );
  }
}

class NumberedBullet extends StatelessWidget {
  const NumberedBullet({super.key, required this.index, required this.text});
  final int index;
  final String text;
  @override
  Widget build(BuildContext context) {
    return Padding(
      padding: const EdgeInsets.symmetric(vertical: 6),
      child: Row(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Container(
            width: 22,
            height: 22,
            alignment: Alignment.center,
            child: Text('$index.',
                style: const TextStyle(
                  fontSize: 14,
                  fontWeight: FontWeight.w700,
                )),
          ),
          const Gap(8),
          Expanded(child: Text(text)),
        ],
      ),
    );
  }
}

class StrategyList extends StatelessWidget {
  const StrategyList({
    super.key,
    required this.items,
    this.background,
    this.borderLeft,
  });
  final List<(String, String)> items;
  final Color? background;
  final Color? borderLeft;
  @override
  Widget build(BuildContext context) {
    final scheme = Theme.of(context).colorScheme;

    return CardSurface(
      child: Padding(
        padding: const EdgeInsets.all(8),
        child: Container(
          // 背景の色味は薄く抑えてカードトーンに寄せる
          decoration: BoxDecoration(
            color: background?.withValues(alpha: 0.12),
            borderRadius: BorderRadius.circular(8),
          ),
          padding:
              background == null ? EdgeInsets.zero : const EdgeInsets.all(8),
          child: Column(
            children: [
              for (var i = 0; i < items.length; i++) ...[
                Row(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      '${i + 1}.',
                      style: const TextStyle(
                        fontSize: 16,
                        fontWeight: FontWeight.w700,
                      ),
                    ),
                    const Gap(8),
                    Flexible(
                      child: Text(
                        items[i].$1,
                        style: Theme.of(context).textTheme.titleSmall?.copyWith(
                            fontWeight: FontWeight.w700, fontSize: 16),
                        maxLines: 2,
                        overflow: TextOverflow.ellipsis,
                        softWrap: true,
                      ),
                    ),
                  ],
                ),
                const Gap(6),
                Align(
                  alignment: Alignment.centerLeft,
                  child: Text(
                    items[i].$2,
                    style: Theme.of(context)
                        .textTheme
                        .bodyMedium
                        ?.copyWith(color: scheme.onSurfaceVariant),
                  ),
                ),
                if (i != items.length - 1) const Gap(12),
              ],
            ],
          ),
        ),
      ),
    );
  }
}

class ZonePanel extends StatelessWidget {
  const ZonePanel(
      {super.key,
      required this.title,
      required this.recommended,
      required this.descriptions});
  final String title;
  final List<int> recommended; // 1..9
  final List<String> descriptions;
  @override
  Widget build(BuildContext context) {
    Widget zoneCell(int n) {
      final isRec = recommended.contains(n);
      return Container(
        alignment: Alignment.center,
        decoration: BoxDecoration(
          color: isRec ? const Color(0xFFFFEB3B) : const Color(0xFFF9F9F9),
          border: Border.all(color: const Color(0xFFDDDDDD)),
        ),
        child: Stack(
          alignment: Alignment.center,
          children: [
            Text('$n',
                style: TextStyle(
                    fontWeight: FontWeight.w700,
                    color: Colors.grey.shade700,
                    fontSize: 12)),
            if (isRec)
              const Align(
                child: Padding(
                  padding: EdgeInsets.all(2.0),
                  child: Text('◎',
                      style: TextStyle(
                          color: Color(0xFFF44336),
                          fontSize: 14,
                          fontWeight: FontWeight.w800)),
                ),
              ),
          ],
        ),
      );
    }

    return Column(
      crossAxisAlignment: CrossAxisAlignment.center,
      children: [
        Text(title,
            style: TextStyle(
                color: Colors.grey.shade700, fontWeight: FontWeight.w700)),
        const Gap(8),
        SizedBox(
          width: 120,
          height: 120,
          child: GridView.count(
            crossAxisCount: 3,
            mainAxisSpacing: 0,
            crossAxisSpacing: 0,
            physics: const NeverScrollableScrollPhysics(),
            shrinkWrap: true,
            children: [for (var n = 1; n <= 9; n++) zoneCell(n)],
          ),
        ),
        const Gap(12),
        Assets.images.icHomePlate.svg(
            width: 88,
            colorFilter: ColorFilter.mode(
              const Color(0xFFDDDDDD),
              BlendMode.srcIn,
            )),
        const Gap(12),
        Container(
          padding: const EdgeInsets.all(8),
          width: 160,
          decoration: BoxDecoration(
            color: const Color(0xFFF0F2F5),
            borderRadius: BorderRadius.circular(6),
          ),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              for (final d in descriptions)
                Padding(
                  padding: const EdgeInsets.symmetric(vertical: 2),
                  child: Text(d, style: const TextStyle(fontSize: 12)),
                ),
            ],
          ),
        ),
      ],
    );
  }
}

class CardSurface extends StatelessWidget {
  const CardSurface({super.key, required this.child});
  final Widget child;
  @override
  Widget build(BuildContext context) {
    final scheme = Theme.of(context).colorScheme;
    return Container(
      decoration: BoxDecoration(
        color: scheme.surface,
        borderRadius: BorderRadius.circular(12),
        boxShadow: [
          BoxShadow(
            color: Colors.black.withValues(alpha: 0.06),
            blurRadius: 12,
            offset: const Offset(0, 6),
          ),
        ],
      ),
      child: child,
    );
  }
}

