// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/ai_coach/count_recommendations.dart';
import 'package:baseball_detector_flutter/views/pages/ai_coach_report/components/common.dart';
import 'package:baseball_detector_flutter/views/pages/ai_coach_report/components/expansion_tile_card.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/hooks/use_pitch_type_map.dart';

class CountStrategyExpansionTile extends HookConsumerWidget {
  const CountStrategyExpansionTile({
    required this.entries,
    this.titleStyle,
    this.subtitleStyle,
    super.key,
  });

  final List<CountRecommendationsEntry> entries;
  final TextStyle? titleStyle;
  final TextStyle? subtitleStyle;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final theme = Theme.of(context);
    final scheme = theme.colorScheme;
    final translatePitchType = useTranslatePitchType();
    final pitchTypeColor = usePitchTypeColor();
    final effectiveTitleStyle = titleStyle ??
        theme.textTheme.titleMedium?.copyWith(
          fontWeight: FontWeight.w600,
          color: scheme.onSurface,
        );
    final effectiveSubtitleStyle = subtitleStyle ??
        theme.textTheme.bodySmall?.copyWith(
          color: scheme.onSurfaceVariant,
        );

    return ExpansionTileCard(
      titleBuilder: (icon) => Row(
        mainAxisAlignment: MainAxisAlignment.spaceBetween,
        children: [
          Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Text(
                'カウント別推奨配球',
                style: effectiveTitleStyle,
              ),
              const Gap(4),
              Text(
                '${entries.length} カウント分析済み',
                style: effectiveSubtitleStyle,
              ),
            ],
          ),
          icon,
        ],
      ),
      children: entries
          .map(
            (entry) => CardSurface(
              child: Padding(
                padding: const EdgeInsets.all(12),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Row(
                      children: [
                        Container(
                          padding: const EdgeInsets.symmetric(
                              horizontal: 12, vertical: 6),
                          decoration: BoxDecoration(
                            color: const Color(0xFFf3f4f6),
                            border: Border.all(color: const Color(0xFFe5e7eb)),
                            borderRadius: BorderRadius.circular(8),
                          ),
                          child: Text(
                            entry.count,
                            style: const TextStyle(
                              fontSize: 14,
                              fontWeight: FontWeight.w700,
                            ),
                          ),
                        ),
                      ],
                    ),
                    if (entry.recommendations.isNotEmpty) ...[
                      const Gap(8),
                      Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          for (var i = 0;
                              i < entry.recommendations.length;
                              i++) ...[
                            Row(
                              crossAxisAlignment: CrossAxisAlignment.start,
                              children: [
                                Row(
                                  children: [
                                    Container(
                                      width: 6,
                                      height: 24,
                                      color: pitchTypeColor(entry
                                          .recommendations[i]
                                          .pitchType
                                          .pitchType),
                                    ),
                                    const Gap(8),
                                    Text(
                                      translatePitchType(entry
                                          .recommendations[i]
                                          .pitchType
                                          .pitchType),
                                      style:
                                          theme.textTheme.titleSmall?.copyWith(
                                        fontWeight: FontWeight.w600,
                                        color: scheme.onSurface,
                                      ),
                                    ),
                                  ],
                                ),
                                const Gap(8),
                                Expanded(
                                  child: Text(
                                    entry.recommendations[i].note,
                                    style: TextStyle(
                                        color: scheme.onSurfaceVariant),
                                  ),
                                ),
                              ],
                            ),
                            if (i != entry.recommendations.length - 1)
                              const Gap(8),
                          ],
                        ],
                      ),
                    ],
                  ],
                ),
              ),
            ),
          )
          .toList(),
    );
  }
}

